title_zh: "星世线小程序增长与体验优化"
title_en: "Xingshixian Mini-Program Growth & UX Optimization"
period: "2022.10 — 2023.01"
role_zh: "项目负责人"
role_en: "Project Lead"
tags: ["用户调研", "交互设计", "Figma", "数据分析", "竞品分析"]
